+
+function encodeValue(value, label) {
+  if (value === undefined) {
+    return { kind: "unit" };
+  }
+  if (typeof value === "boolean") {
+    return { kind: "bool", value };
+  }
+  if (typeof value === "number") {
+    if (!Number.isFinite(value) || !Number.isInteger(value)) {
